import React from 'react';
import { clsx } from 'clsx';
import { useScrollReveal } from '../hooks';
import { FEATURES } from '../utils';
import { SectionHeader, Icon } from './ui';

const FeatureCard = ({ feature, index }) => {
  const [ref, isVisible] = useScrollReveal();

  return (
    <div
      ref={ref}
      className={clsx(
        'bg-white p-12 rounded-[20px] relative overflow-hidden transition-all duration-500 ease-out-expo border border-transparent group',
        'hover:-translate-y-2 hover:shadow-[0_30px_60px_-20px_rgba(0,0,0,0.15)] hover:border-primary/5',
        'opacity-0 translate-y-10',
        isVisible && 'opacity-100 translate-y-0'
      )}
      style={{ transitionDelay: `${index * 100}ms` }}
    >
      {/* Left Accent Line */}
      <div className="absolute top-0 left-0 w-1 h-0 bg-gold transition-all duration-500 ease-out-expo group-hover:h-full" />

      {/* Number */}
      <span className="absolute top-6 right-8 font-serif text-6xl italic text-light-gray leading-none transition-colors duration-400 group-hover:text-gold/30">
        {feature.number}
      </span>

      {/* Icon */}
      <div className="w-[52px] h-[52px] flex items-center justify-center bg-cream rounded-[14px] mb-6 transition-all duration-500 ease-out-expo group-hover:bg-gold group-hover:rotate-[-5deg]">
        <Icon
          name={feature.icon}
          size={24}
          className="text-charcoal transition-colors duration-400 group-hover:text-primary"
        />
      </div>

      {/* Content */}
      <h3 className="text-xl font-semibold mb-3 tracking-tight">{feature.title}</h3>
      <p className="text-warm-gray leading-relaxed text-[15px]">{feature.description}</p>
    </div>
  );
};

const Features = () => {
  return (
    <section className="section section-light" id="features">
      <div className="container">
        <SectionHeader
          number="01"
          title="Built for"
          titleHighlight="Security"
          description="We provide a trusted, centralized location for storing your most important documents with professional-grade protection."
        />

        <div className="grid md:grid-cols-2 gap-6">
          {FEATURES.map((feature, index) => (
            <FeatureCard key={feature.number} feature={feature} index={index} />
          ))}
        </div>
      </div>
    </section>
  );
};

export default Features;
